import React from "react"
import { graphql, Link } from "gatsby"
import { Layout } from "../components/Layout"
import { Helmet } from "react-helmet"
import { getMemberImageUrl, getPhotoUrl } from "../utils/imageUrl"

const backLinkStyle = {
  display: "inline-flex",
  alignItems: "center",
  gap: "0.5rem",
  marginBottom: "2rem",
  fontSize: "0.95rem",
  color: "var(--color-text-muted)",
}

const wrapStyle = {
  maxWidth: 640,
  margin: "0 auto",
}

const nameStyle = {
  margin: "0 0 0.5rem",
  fontSize: "clamp(1.75rem, 4vw, 2.5rem)",
  fontWeight: 800,
  color: "var(--color-text)",
}

const roleStyle = {
  margin: 0,
  fontSize: "1.15rem",
  color: "var(--color-text-muted)",
}

const bioStyle = {
  margin: "1.5rem 0",
  fontSize: "1.05rem",
  lineHeight: 1.7,
  color: "var(--color-text)",
}

const sectionTitleStyle = {
  margin: "2rem 0 0.75rem",
  fontSize: "0.85rem",
  fontWeight: 600,
  textTransform: "uppercase",
  letterSpacing: "0.05em",
  color: "var(--color-text-muted)",
}

const linkListStyle = {
  listStyle: "none",
  margin: 0,
  padding: 0,
  display: "flex",
  flexWrap: "wrap",
  gap: "0.75rem",
}

const linkItemStyle = {
  display: "inline-block",
  padding: "0.5rem 1rem",
  background: "var(--color-surface)",
  border: "1px solid var(--color-border)",
  borderRadius: 8,
  color: "var(--color-accent)",
  fontWeight: 500,
  transition: "background 0.15s ease, border-color 0.15s ease",
}

const avatarWrapStyle = {
  marginBottom: "1.5rem",
}

const avatarStyle = {
  width: 120,
  height: 120,
  borderRadius: "50%",
  objectFit: "cover",
  border: "3px solid var(--color-border)",
}

const galleryGridStyle = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fill, minmax(240px, 1fr))",
  gap: "1.25rem",
  marginTop: "0.75rem",
}

const galleryItemStyle = {
  background: "var(--color-surface)",
  border: "1px solid var(--color-border)",
  borderRadius: 12,
  overflow: "hidden",
  boxShadow: "var(--shadow)",
}

const galleryImgStyle = {
  width: "100%",
  aspectRatio: "4/3",
  objectFit: "cover",
  display: "block",
}

const galleryCaptionStyle = {
  margin: 0,
  padding: "0.75rem 1rem",
  fontSize: "0.9rem",
  lineHeight: 1.4,
  color: "var(--color-text-muted)",
}

export default function MemberLanding({ data, pageContext }) {
  const { slug } = pageContext
  const member = (data.allMembersJson?.nodes || []).find(
    (n) => n.parent?.relativeDirectory === slug
  ) || null

  if (!member) {
    return (
      <Layout>
        <p>Miembro no encontrado.</p>
        <Link to="/">Volver al inicio</Link>
      </Layout>
    )
  }

  const { name, role, bio, links, email, avatar, photos } = member
  const avatarUrl = getMemberImageUrl(avatar, slug)

  return (
    <Layout>
      <Helmet>
        <title>{name} | Alumni CMLP51</title>
        <meta name="description" content={bio || `Landing de ${name}`} />
      </Helmet>
      <Link to="/" style={backLinkStyle} className="back-link">
        ← Volver a miembros
      </Link>
      <div style={wrapStyle}>
        {avatarUrl && (
          <div style={avatarWrapStyle}>
            <img src={avatarUrl} alt="" style={avatarStyle} />
          </div>
        )}
        <h1 style={nameStyle}>{name}</h1>
        {role && <p style={roleStyle}>{role}</p>}
        {bio && <p style={bioStyle}>{bio}</p>}

        {photos && photos.length > 0 && (
          <>
            <h2 style={sectionTitleStyle}>Galería</h2>
            <div style={galleryGridStyle} className="member-gallery">
              {photos.map((photo, i) => {
                const photoUrl = getPhotoUrl(photo, slug)
                if (!photoUrl) return null
                return (
                  <figure key={i} style={galleryItemStyle}>
                    <img src={photoUrl} alt={photo.description || ""} style={galleryImgStyle} />
                    {photo.description && (
                      <figcaption style={galleryCaptionStyle}>{photo.description}</figcaption>
                    )}
                  </figure>
                )
              })}
            </div>
          </>
        )}

        {(email || (links && links.length > 0)) && (
          <>
            <h2 style={sectionTitleStyle}>Contacto</h2>
            <ul style={linkListStyle}>
              {email && (
                <li>
                  <a href={`mailto:${email}`} style={linkItemStyle}>
                    Email
                  </a>
                </li>
              )}
              {links &&
                links.map((link, i) => (
                  <li key={i}>
                    <a
                      href={link.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      style={linkItemStyle}
                    >
                      {link.label}
                    </a>
                  </li>
                ))}
            </ul>
          </>
        )}
      </div>
    </Layout>
  )
}

export const query = graphql`
  query MemberLanding {
    allMembersJson {
      nodes {
        name
        role
        bio
        avatar
        email
        links {
          label
          url
        }
        photos {
          file
          url
          description
        }
        parent {
          ... on File {
            relativeDirectory
          }
        }
      }
    }
  }
`
